Berikut adalah implementasi fungsi Python untuk membandingkan dua dictionary secara rekursif. Fungsi ini dirancang untuk menangani nested dictionary, list, dan tipe data primitif, serta mengembalikan struktur perbedaan yang jelas (added, removed, changed).

```python
from typing import Any, Dict, Tuple, List, Union

def diff_dicts(dict1: Dict, dict2: Dict, path: str = "") -> Dict[str, Any]:
    """
    Recursively diff two dictionaries and return differences.

    Returns:
        Dict with keys: 'added', 'removed', 'changed', 'unchanged'
    """
    result = {
        'added': {},
        'removed': {},
        'changed': {},
        'unchanged': {}
    }

    all_keys = set(dict1.keys()) | set(dict2.keys())

    for key in all_keys:
        current_path = f"{path}.{key}" if path else key

        if key not in dict1:
            result['added'][current_path] = dict2[key]
        elif key not in dict2:
            result['removed'][current_path] = dict1[key]
        else:
            val1, val2 = dict1[key], dict2[key]

            if type(val1) != type(val2):
                result['changed'][current_path] = {
                    'old': val1,
                    'new': val2,
                    'reason': 'type_mismatch'
                }
            elif isinstance(val1, dict) and isinstance(val2, dict):
                nested_diff = diff_dicts(val1, val2, current_path)

                for diff_type in ['added', 'removed', 'changed']:
                    if nested_diff[diff_type]:
                        result[diff_type].update(nested_diff[diff_type])

                if nested_diff['unchanged']:
                    result['unchanged'].update(nested_diff['unchanged'])

            elif isinstance(val1, list) and isinstance(val2, list):
                if val1 != val2:
                    result['changed'][current_path] = {
                        'old': val1,
                        'new': val2,
                        'reason': 'list_mismatch'
                    }
                else:
                    result['unchanged'][current_path] = val1
            else:
                if val1 != val2:
                    result['changed'][current_path] = {
                        'old': val1,
                        'new': val2
                    }
                else:
                    result['unchanged'][current_path] = val1

    return result


def diff_dicts_simple(dict1: Dict, dict2: Dict) -> Tuple[Dict, Dict, Dict]:
    """
    Simplified version returning only (added, removed, changed).
    More suitable for production use where unchanged keys are irrelevant.
    """
    added = {}
    removed = {}
    changed = {}

    def compare(d1: Any, d2: Any, path: str = ""):
        if isinstance(d1, dict) and isinstance(d2, dict):
            all_keys = set(d1.keys()) | set(d2.keys())

            for key in all_keys:
                current_path = f"{path}.{key}" if path else key

                if key not in d1:
                    added[current_path] = d2[key]
                elif key not in d2:
                    removed[current_path] = d1[key]
                elif d1[key] != d2[key]:
                    if isinstance(d1[key], dict) and isinstance(d2[key], dict):
                        compare(d1[key], d2[key], current_path)
                    else:
                        changed[current_path] = {'old': d1[key], 'new': d2[key]}

    compare(dict1, dict2)
    return added, removed, changed


# =====================
# Usage Examples
# =====================

if __name__ == "__main__":
    dict_a = {
        'server': {
            'host': '192.168.1.1',
            'port': 8080,
            'ssl': True
        },
        'database': {
            'name': 'prod_db',
            'users': ['admin', 'user1']
        },
        'debug': False
    }

    dict_b = {
        'server': {
            'host': '192.168.1.2',
            'port': 8080,
            'timeout': 30
        },
        'database': {
            'name': 'prod_db',
            'users': ['admin', 'user1', 'user2']
        },
        'cache': {
            'enabled': True
        }
    }

    # Full diff
    full_result = diff_dicts(dict_a, dict_b)
    print("=== FULL DIFF ===")
    print(f"Added: {full_result['added']}")
    print(f"Removed: {full_result['removed']}")
    print(f"Changed: {full_result['changed']}")

    # Simple diff
    added, removed, changed = diff_dicts_simple(dict_a, dict_b)
    print("\n=== SIMPLE DIFF ===")
    print(f"Added: {added}")
    print(f"Removed: {removed}")
    print(f"Changed: {changed}")
```

